#!/usr/bin/perl

use strict;
use warnings;

my $filename = $ARGV[0];

open my $fh, '<', $filename or die "Cannot open file '$filename': $!";

my %word_count;
while (my $line = <$fh>) {
    chomp $line;
    foreach my $word (split /\s+/, lc $line) {
        $word_count{$word}++;
    }
}

close $fh;

my @sorted_words = sort { $word_count{$b} <=> $word_count{$a} } keys %word_count;

print "$_: $word_count{$_}\n" for @sorted_words[0..2];

